"""Detect, decode and OCR base64-encoded images embedded in the markdown.

Images appear inline as: ``![](data:image/png;base64,<b64>)``
We decode them, run OCR and cache results on disk keyed by a content hash so
repeated ingestion runs are cheap.
"""
from __future__ import annotations

import base64
import binascii
import hashlib
import io
import json
import re
from pathlib import Path

# Matches markdown images embedding base64 data URIs (png/jpeg/gif/webp).
DATA_URI_RE = re.compile(
    r"!\[[^\]]*\]\(data:image/(?P<fmt>[a-zA-Z]+);base64,(?P<data>[A-Za-z0-9+/=\s]+?)\)"
)


def find_base64_images(text: str) -> list[str]:
    """Return the raw base64 payloads of every embedded image in ``text``."""
    return [m.group("data").strip() for m in DATA_URI_RE.finditer(text)]


def strip_image_markup(text: str) -> str:
    """Remove the (very long) base64 image markup from text, leaving a marker."""
    return DATA_URI_RE.sub(" [IMAGE] ", text).strip()


class OcrCache:
    """Simple JSON-file cache mapping image hash -> extracted text."""

    def __init__(self, cache_path: Path):
        self.cache_path = cache_path
        self._data: dict[str, str] = {}
        if cache_path.exists():
            try:
                self._data = json.loads(cache_path.read_text(encoding="utf-8"))
            except json.JSONDecodeError:
                self._data = {}

    def get(self, key: str) -> str | None:
        return self._data.get(key)

    def set(self, key: str, value: str) -> None:
        self._data[key] = value

    def flush(self) -> None:
        self.cache_path.parent.mkdir(parents=True, exist_ok=True)
        self.cache_path.write_text(
            json.dumps(self._data, ensure_ascii=False, indent=2), encoding="utf-8"
        )


def _decode_image(b64: str):
    """Decode a base64 string into a PIL image (or None on failure)."""
    try:
        from PIL import Image  # local import keeps Pillow optional
    except ImportError:  # pragma: no cover
        return None
    try:
        raw = base64.b64decode(b64)
        return Image.open(io.BytesIO(raw)).convert("RGB")
    except (binascii.Error, OSError, ValueError):
        return None


def _ocr_tesseract(image) -> str:
    import pytesseract

    return pytesseract.image_to_string(image)


def _ocr_easyocr(image) -> str:
    import numpy as np
    import easyocr

    reader = easyocr.Reader(["en"], gpu=False)
    result = reader.readtext(np.array(image), detail=0)
    return " ".join(result)


def ocr_image(b64: str, engine: str = "tesseract") -> str:
    """Run OCR on a single base64 image, returning cleaned extracted text."""
    image = _decode_image(b64)
    if image is None:
        return ""
    # Upscale tiny pictograms so OCR has a chance.
    if min(image.size) < 64:
        scale = 64 // min(image.size) + 1
        image = image.resize((image.width * scale, image.height * scale))
    try:
        text = _ocr_easyocr(image) if engine == "easyocr" else _ocr_tesseract(image)
    except Exception:  # noqa: BLE001 - OCR engines raise varied errors / missing deps
        return ""
    # Normalise whitespace.
    return re.sub(r"\s+", " ", text).strip()


def ocr_text_for(text: str, cache: OcrCache, engine: str = "tesseract") -> str:
    """OCR every image embedded in ``text`` and return the concatenated text."""
    extracted: list[str] = []
    for b64 in find_base64_images(text):
        key = hashlib.sha1(b64.encode("utf-8")).hexdigest()
        cached = cache.get(key)
        if cached in [None, ""]:
            cached = ocr_image(b64, engine=engine)
            cache.set(key, cached)
        if cached:
            extracted.append(cached)
    return " ".join(extracted).strip()

if __name__=="__main__":
    from faq_rag.config import get_settings
    settings = get_settings()
    cache = OcrCache(settings.data_path / "ocr_cache.json")
    text="""![](data:image/png;base64,)Chart 1: What undertakings should report and by when
* Article 8 (2) and (3) Disclosures Delegated Act stipulates that information disclosed in accordance with this Regulation shall cover the annual reporting period from the previous calendar year of the date of disclosure and that financial undertakings and non-financial undertakings shall provide in the non-financial statement the key performance indicators covering the previous annual reporting period. Therefore, the first reporting period concerns the (fiscal) year of 2021. 
"""
    result=ocr_text_for(text, cache)
    print(result)
    cache.flush()
